#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, E;
        scanf("%d %d", &n, &E);
        int* x = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &x[i]);
        }
        int sum = 0;
        for (int i = 0; i < n; i++) {
            sum += x[i];
        }
        if (sum < E) {
            printf("-1\n");
        } else {
            int minIndex = 0;
            int minVal = x[0];
            for (int i = 1; i < n; i++) {
                if (x[i] < minVal) {
                    minIndex = i;
                    minVal = x[i];
                }
            }
            double p = (double) E / minVal;
            for (int i = 0; i < n; i++) {
                if (i == minIndex) {
                    printf("%.6f ", p);
                } else {
                    printf("0.000000 ");
                }
            }
            printf("\n");
        }
        free(x);
    }
    return 0;
}

