import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int E = sc.nextInt();
            int[] x = new int[n];
            for (int i = 0; i < n; i++) {
                x[i] = sc.nextInt();
            }
            int sum = 0;
            for (int i = 0; i < n; i++) {
                sum += x[i];
            }
            if (sum < E) {
                System.out.println(-1);
            } else {
                int minIndex = 0;
                int minVal = x[0];
                for (int i = 1; i < n; i++) {
                    if (x[i] < minVal) {
                        minIndex = i;
                        minVal = x[i];
                    }
                }
                double p = (double) E / minVal;
                for (int i = 0; i < n; i++) {
                    if (i == minIndex) {
                        System.out.printf("%.6f ", p);
                    } else {
                        System.out.printf("%.6f ", 0.0);
                    }
                }
                System.out.println();
            }
        }
    }
}

