code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [n, E] = readline().split(' ').map(Number);
    const x = readline().split(' ').map(Number);
    const sum = x.reduce((a, b) => a + b, 0);
    if (sum < E) {
        console.log(-1);
    } else {
        const minVal = Math.min(...x);
        const minIndex = x.indexOf(minVal);
        const p = E / minVal;
        for (let j = 0; j < n; j++) {
            if (j === minIndex) {
                process.stdout.write(`${p.toFixed(6)} `);
            } else {
                process.stdout.write(`0.000000 `);
            }
        }
        console.log();
    }
}

